import{_ as a,o as s,c as i,a2 as t}from"./chunks/framework.BKG_UbFK.js";const h=JSON.parse('{"title":"Migrar desde una instalación de Spatie existente","description":"","frontmatter":{},"headers":[],"relativePath":"es/guide/migration.md","filePath":"es/guide/migration.md"}'),o={name:"es/guide/migration.md"};function c(n,e,l,d,r,p){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="migrar-desde-una-instalacion-de-spatie-existente" tabindex="-1">Migrar desde una instalación de Spatie existente <a class="header-anchor" href="#migrar-desde-una-instalacion-de-spatie-existente" aria-label="Permalink to &quot;Migrar desde una instalación de Spatie existente&quot;">​</a></h1><p>Si tu aplicación ya usa <code>spatie/laravel-permission</code> con roles, permisos y asignaciones existentes, <code>clearance:install</code> los detecta y los preserva - nunca ejecuta las migraciones de Spatie si la tabla <code>roles</code> ya existe. Consulta <a href="/clearance-docs/es/guide/installation.html">Instalación</a> para el flujo completo de instalación.</p><p>Una vez instalado, usa <code>clearance:backfill</code> para adoptar los propios metadatos de Clearance sobre tus roles y guards existentes.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # meta + role scope + guards</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --only=meta</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # just one section</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # preview, no writes</span></span></code></pre></div><h2 id="que-hace-cada-seccion" tabindex="-1">Qué hace cada sección <a class="header-anchor" href="#que-hace-cada-seccion" aria-label="Permalink to &quot;Qué hace cada sección&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Sección</th><th>Efecto</th></tr></thead><tbody><tr><td><code>meta</code></td><td>Genera un nombre de visualización en <code>clr_meta</code> (nombre del rol en formato título) para cada rol que no tenga uno.</td></tr><tr><td><code>roles</code></td><td>Genera valores predeterminados en <code>clr_role_meta</code> (<code>scope=global</code>, <code>is_locked=false</code>) para cada rol que no tenga uno.</td></tr><tr><td><code>guards</code></td><td>Importa guards desde <code>config(&#39;auth.guards&#39;)</code> a <code>clr_guards</code>, filtrados por <code>allowed_guard_drivers</code>.</td></tr></tbody></table><p>Usa <code>--only=&lt;section&gt;</code> para ejecutar una sola sección en lugar de las tres.</p><div class="tip custom-block"><p class="custom-block-title">Idempotente</p><p>Todas las secciones son idempotentes - volver a ejecutar <code>clearance:backfill</code> es seguro y no duplicará ni sobrescribirá filas <code>clr_*</code> existentes.</p></div><h2 id="casos-especiales" tabindex="-1">Casos especiales <a class="header-anchor" href="#casos-especiales" aria-label="Permalink to &quot;Casos especiales&quot;">​</a></h2><p>El repositorio del paquete tiene una guía de migración más detallada que cubre casos especiales no resumidos aquí - en particular qué ocurre cuando tu base de datos ya tiene un rol llamado <code>super_admin</code> (o un alias como <code>superadmin</code>, <code>root</code>, <code>owner</code>) que entra en conflicto con el propio rol <code>super_admin</code> de Clearance, y notas sobre subclases de modelo <code>Role</code>/<code>Permission</code> personalizadas y el comportamiento de importación de guards. Léela antes de hacer un backfill sobre una base de datos de producción con datos de rol existentes no triviales. Consulta también <a href="/clearance-docs/es/features/super-admin.html">Super Admin</a> para el comportamiento de detección de alias durante <code>clearance:install</code>.</p><h2 id="relacionado" tabindex="-1">Relacionado <a class="header-anchor" href="#relacionado" aria-label="Permalink to &quot;Relacionado&quot;">​</a></h2><ul><li><a href="/clearance-docs/es/guide/installation.html">Instalación</a> - el flujo completo de <code>clearance:install</code></li><li><a href="/clearance-docs/es/api/artisan-commands.html">Comandos Artisan</a> - referencia completa de comandos</li><li><a href="/clearance-docs/es/guide/architecture.html">Arquitectura</a> - las tablas <code>clr_*</code> que el backfill rellena</li></ul>`,12)])])}const m=a(o,[["render",c]]);export{h as __pageData,m as default};
